interface.definition:
#"SYSTEM_SYSRULES_formLayout"(
  titleBar: #"SYSTEM_SYSRULES_headerTemplateSimple"(
    title: "Create / Update City",
    secondaryText: "Fill in the fields below and click Save."
  ),
  contents: {
    #"SYSTEM_SYSRULES_textField"(label: "cityName", value: ri!record.cityName, saveInto: ri!record.cityName, required: true),
    #"SYSTEM_SYSRULES_textField"(label: "countryCode", value: ri!record.countryCode, saveInto: ri!record.countryCode, required: false),
    #"SYSTEM_SYSRULES_floatingPointField"(label: "longitude", value: ri!record.longitude, saveInto: ri!record.longitude),
    #"SYSTEM_SYSRULES_floatingPointField"(label: "latitude", value: ri!record.latitude, saveInto: ri!record.latitude),
    #"SYSTEM_SYSRULES_textField"(label: "timezone", value: ri!record.timezone, saveInto: ri!record.timezone, required: false),
    #"SYSTEM_SYSRULES_checkboxField_v1"(label: "isActive", value: ri!record.isActive, saveInto: ri!record.isActive, choiceLabels: {"Yes"}, choiceValues: {true})
  },
  buttons: #"SYSTEM_SYSRULES_buttonLayout"(
    primaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Save", submit: true, style: "PRIMARY")
    },
    secondaryButtons: {
      #"SYSTEM_SYSRULES_buttonWidget_v1"(label: "Cancel", value: true, saveInto: ri!cancel, submit: true, validate: false)
    }
  )
)
